USE PharmacyDB;
GO

-- Fix DispensationItems (không có SubTotal)
DELETE FROM DispensationItems WHERE Id LIKE '40000000%';

-- Fix InvoiceItems (không có SubTotal)
DELETE FROM InvoiceItems WHERE Id LIKE '60000000%';

-- Kiểm tra kết quả
SELECT '=== USERS ===' AS T, COUNT(*) N FROM Users
UNION ALL SELECT '=== MEDICINES ===', COUNT(*) FROM Medicines WHERE IsDeleted=0
UNION ALL SELECT '=== DISPENSATIONS ===', COUNT(*) FROM Dispensations WHERE IsDeleted=0
UNION ALL SELECT '=== DISP ITEMS ===', COUNT(*) FROM DispensationItems WHERE IsDeleted=0
UNION ALL SELECT '=== INVOICES ===', COUNT(*) FROM Invoices WHERE IsDeleted=0
UNION ALL SELECT '=== INVOICE ITEMS ===', COUNT(*) FROM InvoiceItems WHERE IsDeleted=0;

-- Xem 3 thuốc sắp hết kho
SELECT TOP 5 MedicineCode, Name, StockQuantity, MinimumStock FROM Medicines
WHERE StockQuantity <= MinimumStock AND IsDeleted=0 ORDER BY StockQuantity;
